body:
Can you attach an example that shows the issue?  

```
package uvm_pkg;
typedef enum bit [1:0]
{
  UVM_INFO,
  UVM_ERROR
} uvm_severity;
typedef enum
{
  UVM_NONE   = 0
} uvm_verbosity;
virtual class uvm_object;
  extern virtual function string get_name ();
endclass
function string uvm_object::get_name ();
endfunction
virtual class uvm_transaction extends uvm_object;
endclass
class uvm_sequence_item extends uvm_transaction;
  function int uvm_report_enabled(int verbosity, int severity=UVM_INFO, string id="");
  endfunction
  virtual function void uvm_report_error( string id,
					  string message,
   					  int verbosity = UVM_NONE,
					  string filename = "",
					  int line = 0,
   					  string context_name = "",
					  bit report_enabled_checked = 0);
  endfunction
endclass
endpackage
package tb_cpu_pkg;
   import uvm_pkg::*;
     class tb_cpu_seq_item extends uvm_sequence_item; 
     virtual function string get_type_name(); 
     endfunction : get_type_name
    virtual function bit do_compare( tb_cpu_seq_item rhs, int comparer);
       string fn = {get_name, ".do_compare"};
   begin 
     if (uvm_report_enabled(UVM_NONE,UVM_ERROR,fn)) 
       uvm_report_error (fn, $sformatf("this is of type %s, rhs is of type %s", this.get_type_name, rhs.get_type_name), UVM_NONE, "", 0, "", 1); 
   end
    endfunction
endclass : tb_cpu_seq_item
endpackage : tb_cpu_pkg;
module tb_cpu;
endmodule
```

```
verilator --cc --timing -Wno-fatal --top-module tb_cpu test.sv
%Error: test4.sv:40:86: Found definition of 'get_type_name' as a FUNC but expected a variable
   40 |        uvm_report_error (fn, $sformatf("this is of type %s, rhs is of type %s", this.get_type_name, rhs.get_type_name), UVM_NONE, "", 0, "", 1); 
      |                                                                                      ^~~~~~~~~~~~~
```

With this change:

```
40c40
<        uvm_report_error (fn, $sformatf("this is of type %s, rhs is of type %s", this.get_type_name, rhs.get_type_name), UVM_NONE, "", 0, "", 1); 
---
>        uvm_report_error (fn, $sformatf("this is of type %s, rhs is of type %s", this.get_type_name(), rhs.get_type_name), UVM_NONE, "", 0, "", 1); 
```

compiles:

```
verilator --cc --timing -Wno-fatal --top-module tb_cpu test4.sv
%Warning-WIDTHEXPAND: test4.sv:19:54: Operator VAR 'severity' expects 32 bits on the Initial value, but Initial value's ENUMITEMREF 'UVM_INFO' generates 2 bits.
                                    : ... note: In instance 'tb_cpu'
   19 |   function int uvm_report_enabled(int verbosity, int severity=UVM_INFO, string id="");
      |                                                      ^~~~~~~~
                      ... For warning description see https://verilator.org/warn/WIDTHEXPAND?v=5.037
                      ... Use "/* verilator lint_off WIDTHEXPAND */" and lint_on around source to disable this message.
%Warning-WIDTHEXPAND: test4.sv:39:10: Operator FUNCREF 'uvm_report_enabled' expects 32 bits on the Function Argument, but Function Argument's ENUMITEMREF 'UVM_ERROR' generates 2 bits.
                                    : ... note: In instance 'tb_cpu'
   39 |      if (uvm_report_enabled(UVM_NONE,UVM_ERROR,fn)) 
      |          ^~~~~~~~~~~~~~~~~~
%Warning-WIDTHTRUNC: test4.sv:39:6: Logical operator IF expects 1 bit on the If, but If's FUNCREF 'uvm_report_enabled' generates 32 bits.
                                  : ... note: In instance 'tb_cpu'
   39 |      if (uvm_report_enabled(UVM_NONE,UVM_ERROR,fn)) 
      |      ^~
```

**NOTE** `rhs.get_type_name` does not have parentheses.

VCS compiles both versions without problem.

What 'verilator' command line do we use to run your example?

```
verilator --cc --timing -Wno-fatal --top-module tb_cpu test.sv
```

What 'verilator --version' are you using?  Did you try it with the git master version?

`Verilator 5.037 devel rev v5.036-162-g51545b36c`

What OS and distribution are you using?

`Linux 5.14.0-570.19.1.el9_6.x86_64`

